import{_ as o,M as p,p as c,q as l,Q as s,N as t,a1 as e,t as n}from"./framework-7d8e42ec.js";const i="/element-component/assets/作用域链-e3bdc77c.png",u={},r=e(`<h1 id="嗨-你知道-let-和-const-吗" tabindex="-1"><a class="header-anchor" href="#嗨-你知道-let-和-const-吗" aria-hidden="true">#</a> 嗨，你知道 let 和 const 吗？</h1><h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>如果有人问你：知道 let 和 const 吗 答案是肯定的，还能回答的头头是道：</p><ul><li>let 和 const 不就是 es6 新增的声明变量的关键字嘛</li><li>let 是用来声明变量的，const 是用来声明常量的</li><li>与 var 不同，let、const 不存在变量提升</li><li>暂时性死区</li><li>不绑定顶级对象</li></ul><p>再问：</p><ul><li>let 和 const 真的不存在变量提升吗？ 为什么不存在</li><li>暂时性死区又是如何形成的？</li><li>let、const 声明的全局变量不在 全局对象中，那它存在于哪里呢？</li></ul><h2 id="_1-var-的变量提升规则" tabindex="-1"><a class="header-anchor" href="#_1-var-的变量提升规则" aria-hidden="true">#</a> 1. var 的变量提升规则</h2><p>复习变量提升的概念，其中涉及到 JS 的 <strong>执行上下文、变量对象</strong> 等知识。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> a <span class="token operator">=</span> <span class="token string">&quot;global&quot;</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token parameter">a</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>temp<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
    <span class="token keyword">var</span> temp <span class="token operator">=</span> <span class="token string">&quot;local&quot;</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>我们都知道在 js 中，代码执行时会把当前作用域中的所有的使用 var 声明的变量以及 function 声明的函数提升到作用域的顶部(变量提升声明，不提升赋值；函数提升函数体，不提升调用)。所以我们在 var 声明变量之前可以访问 temp，结果是 <strong>undefined</strong></p><p>让我们从 js 代码的运行角度去看这个过程，如下：</p><div class="custom-container tip"><p class="custom-container-title">执行流程</p><ol><li>执行流进入全局执行环境</li><li>创建全局执行环境的变量对象, 并将变量 a 的声明、函数 bar 的声明添加到变量对象中</li><li>进入全局代码执行阶段</li><li>对变量 a 赋值为 &#39;global&#39;</li><li>遇到 函数 bar 的调用</li><li>进入函数 bar 内部，创建 bar 的执行环境，压入执行环境栈</li><li>同样的，创建函数 bar 执行环境的活动对象，将变量 temp 在 活动对象内创建，key 为 temp，初始化值为 undefined</li><li>进入代码执行阶段，遇到 打印输出 a，此时 a 存在于活动对象中，值为 undefined</li><li>继续执行，为 temp 赋值为 &#39;local&#39;</li><li>bar 函数内代码执行完毕，执行环境栈谈出 bar 执行环境，执行流回到 global 执行环境中继续执行...</li></ol></div><div class="custom-container tip"><p class="custom-container-title">简而言之</p><p>js 在代码预编译阶段，会创建一个变量对象，变量对象中有一个属性，属性名称为 temp，属性值为 undefined，所以在变量声明之前打印 temp，值为 undefined；这也就是 var 的变量提升规则</p></div><h2 id="_2-let-的提升规则" tabindex="-1"><a class="header-anchor" href="#_2-let-的提升规则" aria-hidden="true">#</a> 2. let 的提升规则</h2><h3 id="死缓区-暂存死区-tdz-temporal-dead-zone" tabindex="-1"><a class="header-anchor" href="#死缓区-暂存死区-tdz-temporal-dead-zone" aria-hidden="true">#</a> 死缓区？ 暂存死区？ TDZ (Temporal dead zone)？</h3><p>如果你能理解 var 的提升规则，那么理解 let 的提升将会变得很轻松。 在 MDN 关于 let 的文档中，有这么一句话：</p><blockquote><p><strong>The other difference between var and let is that the latter is initialized to value only when parser evaluates it (see below).</strong></p></blockquote><p>ps: 我的英语极差，MDN 的翻译是这样的：</p><blockquote><p>var 和 let 的不同之处在于后者是在编译时才初始化（见下面）</p></blockquote><p>我使用 有道翻译 是酱紫的：</p><blockquote><p>var 和 let 之间的另一个区别是，后者只有在解析器对其求值时才初始化为 value(参见下面的内容)。</p></blockquote><p>我预感到 MDN 的中文翻译并不准确(因为 var 是在编译时初始化的，可见翻译有问题)，再结合 有道的硬核翻译，我将其理解为：</p><blockquote><p><strong>var 和 let 的不同之处在于后者是在运行时才初始化的</strong></p></blockquote><p>在 MDN 上点击 <code>(见下面)</code> 看到了 暂存死区的概念：</p><div class="custom-container tip"><p class="custom-container-title">暂存死区</p><p>与通过 var 声明的有初始化值 undefined 的变量不同，通过 let 声明的变量直到它们的定义被执行时才初始化。</p><p>在变量初始化前访问该变量会导致 ReferenceError。该变量处在一个自块顶部到初始化处理的“暂存死区”中。</p></div><h3 id="结合例子" tabindex="-1"><a class="header-anchor" href="#结合例子" aria-hidden="true">#</a> 结合例子：</h3><h4 id="例-1" tabindex="-1"><a class="header-anchor" href="#例-1" aria-hidden="true">#</a> 例 1.</h4><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Uncaught ReferenceError: Cannot access &#39;a&#39; before initialization</span>
    <span class="token keyword">let</span> a <span class="token operator">=</span> <span class="token number">123</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>典型的 let 声明变量的例子：<br> 与 var 不同的是，我们无法在 let 声明之前获取该变量；<br> 否则，报错：Cannot access &#39;a&#39; before initialization；<br> 报错信息给到我们，硬核翻译为：无法在初始化之前访问&#39;a&#39;；<br> 从 “无法在初始化之前访问&#39;a&#39;” 是否能够看出写端倪呢？</p><h4 id="例-2" tabindex="-1"><a class="header-anchor" href="#例-2" aria-hidden="true">#</a> 例 2.</h4><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> a <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">;</span>
<span class="token keyword">let</span> b<span class="token punctuation">;</span>
<span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Uncaught ReferenceError: Cannot access &#39;a&#39; before initialization</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">let</span> a <span class="token operator">=</span> <span class="token punctuation">(</span>b <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>结果为：报错 - Uncaught ReferenceError: Cannot access &#39;a&#39; before initialization；</p><p>与 例 1 报的同样的错误；</p><p>我们试想下：</p><p>在匿名函数内，第一个访问的 a，为什么不能获取到外部环境的 a = 3；而是在这里就早早的报错了呢？</p><p>估计很多人就会说：这不就是因为 let 的<strong>暂时性死区</strong>特性嘛；</p><p>在 阮大神的 《es6 入门》 中，对于暂时性死区这样写到：</p><blockquote><p>只要块级作用域内存在 let 命令，它所声明的变量就“绑定”（binding）这个区域，不再受外部的影响。</p></blockquote><p>以及后面的介绍，在我看来只是声明式的告诉了我：在作用域内，无论代码先后顺序，只要在代码中出现了 let a，那么 a 变量就 <strong>“绑定”</strong> 了这个作用域，有没有疑问？ 为什么我声明变量的代码明明还在下面，上面的代码就被绑定了呢，js 不是顺序执行的吗？</p><p>OK，走到了现在，结合 var 的提升规则，是不是可以将 let 理解为：</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><ul><li>使用 let 声明的变量实际上也存在提升，但是与 var 的提升规则不同：</li><li>var 声明的变量是在代码预编译阶段 被创建在了 执行环境的变量对象中，并且将其初始化，初始化值为 undefined；</li><li>而 let 声明的变量，在执行环境<strong>预编译阶段</strong>，被提升到了一个叫做 <strong>“暂存死区”</strong> 的地方，并且没有对其进行<strong>初始化</strong>；</li><li>所以，无论使用 let 声明的变量，声明在代码的任何位置，这个变量一开始就被 <strong>“绑定”</strong> 在了当前执行环境中；</li><li>在进入执行阶段时，只有在 let 声明被执行后，才对这个变量进行了初始化；</li><li>所以，在执行到 let 声明之前，是无法访问这个被 <strong>“绑定”</strong> 的变量的。</li></ul></div><p><strong>进一步验证</strong></p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> a <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">;</span>
<span class="token keyword">let</span> b<span class="token punctuation">;</span>
<span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">let</span> a<span class="token punctuation">;</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
    b <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">;</span>
    a <span class="token operator">=</span> b<span class="token punctuation">;</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>代码顺利执行 <br> 我们将变量 a 的声明提升到了函数的顶部，在进入函数执行阶段，第一句执行的就是 let a; 声明了 a 变量，并将其值初始化为 undefined <br> 所以在下面打印 a 为 undefined <br> 后续代码就不说了...</p><h3 id="小结" tabindex="-1"><a class="header-anchor" href="#小结" aria-hidden="true">#</a> 小结</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><ol><li>其实 let 和 const 也是存在变量提升的，只不过和 var 的提升规则不同，let 是将变量提升到了一个叫做 <strong>“暂存死区”</strong> 的地方，在提升时并没有对其进行初始化，如果去访问 <strong>“暂存死区”</strong> 中的变量，就会报错；</li><li>由于 let 的变量提升是在 “预编译” 阶段完成的，所以在进入执行环境后，无论声明代码在何处，这个被声明的变量就被绑定了，在声明之前访问这个变量，就会报错，也就会形成 代码的 <strong>“暂时性死区”</strong></li><li>在执行环境的执行阶段，在当执行到 let 声明时，那个变量才会 从 <strong>“暂存死区”</strong> 中移除，并对齐初始化为 undefined，所以 使用 let 声明的变量只能在其声明后访问。</li><li>其实在我的理解中，<strong>“暂存死区”</strong> 和 <strong>“暂时性死区”</strong> 并不是一个概念，<strong>“暂存死区”</strong> 亦可称为 <strong>“死缓区”</strong> (死亡缓存区域？ 随便怎么叫了)，<strong>“暂存死区”</strong> 是一个保存 let 声明的变量的地方，正是因为有这个区域的存在，才使得 let 声明的变量能够保证不能再声明前访问变量，继而也就形成了 <strong>“暂时性死区”</strong></li></ol></div><h2 id="_3-全局环境下的-let" tabindex="-1"><a class="header-anchor" href="#_3-全局环境下的-let" aria-hidden="true">#</a> 3. 全局环境下的 let</h2><p>在 《es6 入门》 中如是写到：</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>顶层对象，在浏览器环境指的是 window 对象，在 Node 指的是 global 对象。ES5 之中，顶层对象的属性与全局变量是等价的。</p><p>let 命令、const 命令、class 命令声明的全局变量，不属于顶层对象的属性。</p></div><p>在 es5 时期，全局声明的变量是被挂载在顶级对象下的，在 es6 时期，使用 let 声明的全局变量，并不存在于顶级对象下</p><p>那么问题来了，使用 let 声明的变量存在于哪里呢？</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> a <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
<span class="token keyword">let</span> b <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>a<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>下列涉及到作用域、作用域链生成规则等知识, 如果不理解作用链的生成规则可能会对下面产生疑惑。</p></blockquote>`,53),d=n("友情链接："),k={href:"https://juejin.im/post/6844903975544848397",target:"_blank",rel:"noopener noreferrer"},v=n("了解作用域"),b=n(" | "),m={href:"https://juejin.im/post/6844903975548878856",target:"_blank",rel:"noopener noreferrer"},g=n("深入作用域链"),h=e(`<div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> str <span class="token operator">=</span> <span class="token string">&quot;global Str&quot;</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">let</span> str <span class="token operator">=</span> <span class="token string">&quot;local Str&quot;</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

console<span class="token punctuation">.</span><span class="token function">dir</span><span class="token punctuation">(</span>bar<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出结果：</p><p><img src="`+i+'" alt="作用域链"></p><p>上图中的 圈红部分是函数的作用域链(在 谷歌浏览器可以看到如上的打印输出，在 火狐 ie 下均没有)</p><p>可以看到，在作用域链中存在两项：</p><ul><li><strong><code>[[Scopes]][0]: Script</code></strong> 和顶级对象平行的一个作用域，可以看到里面貌似有熟悉的东西</li><li><strong><code>[[Scopes]][1]: Global</code></strong> 也就是顶级作用域的变量对象，在浏览器中就是 window</li></ul><h3 id="小结-1" tabindex="-1"><a class="header-anchor" href="#小结-1" aria-hidden="true">#</a> 小结</h3><ul><li><p>let 定义的全局变量并不存在于 顶级对象中，而是存在于和顶级对象平行的一个全局作用域中</p></li><li><p>亦或者可以说 let 和 const 定义的变量是存在于作用链的顶端的，根据作用域链的访问规则，可以访问到全局变量</p></li><li><p>至于这个 作用域链顶端的 Script 到底是什么，我也说不清楚，我目前没有仔细去找解释这个 <strong><code>[[Scopes]][0]: Script</code></strong> 的文档，大致的找了下，并没有找到，还望有了解的大佬解释下这个 作用域链 顶端的 Script 到底是个什么东西。</p></li></ul><h2 id="干货总结" tabindex="-1"><a class="header-anchor" href="#干货总结" aria-hidden="true">#</a> 干货总结</h2><ul><li>let 和 const 也存在变量提升，预编译阶段提升，所以能绑定整个作用域</li><li>let 和 const 将变量提升到了一个称为 “死缓区” 的地方，尝试访问 “死缓区” 内容将会报错，所以形成 “暂时性死区”</li><li>let 和 const 在提升变量时不会对其初始化操作</li><li>let 和 cosnt 声明的全局变量在 作用域链的顶端，一个叫 Script 的作用域里，根据作用域链规则，可以访问到其定义的全局变量</li></ul>',10);function f(_,w){const a=p("ExternalLinkIcon");return c(),l("div",null,[r,s("p",null,[d,s("a",k,[v,t(a)]),b,s("a",m,[g,t(a)])]),h])}const x=o(u,[["render",f],["__file","letconst.html.vue"]]);export{x as default};
